head.b:skin:
/*
  Revenue Clarity Pro for Blogger
  - Affiliate and AdSense ready
  - SEO-focused content surfaces
  - No dark mode, no reading progress, no reading-time widget
  - Warm professional editorial design, not news-like and not AI-like
  - Works with standard Blogger layout widgets
*/

/* ==========================================================================
   01. Design tokens
   ========================================================================== */
:root {
  --bg: #f7f4ee;
  --bg-soft: #fbf8f1;
  --surface: #fffdf8;
  --surface-2: #fff8ed;
  --surface-3: #fff4e4;
  --text: #24211d;
  --text-soft: #3a342e;
  --muted: #6e675f;
  --muted-2: #8d8174;
  --line: #e8dfd2;
  --line-strong: #d8c8b2;
  --brand: #9b5c22;
  --brand-2: #c77a2d;
  --brand-3: #7a4316;
  --accent: #236b5e;
  --accent-2: #eff8f5;
  --accent-3: #dceee9;
  --warning: #fff0c7;
  --success: #edf7e9;
  --danger: #fff1ef;
  --shadow: 0 18px 50px rgba(67, 45, 22, .10);
  --shadow-sm: 0 8px 22px rgba(67, 45, 22, .08);
  --radius-xl: 28px;
  --radius: 18px;
  --radius-sm: 12px;
  --radius-pill: 999px;
  --max: 1180px;
  --content: 760px;
  --sidebar: 330px;
  --gap: 34px;
  --font: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Noto Sans KR", "Apple SD Gothic Neo", Arial, sans-serif;
  --serif: Georgia, "Noto Serif KR", serif;
}

/* ==========================================================================
   02. Reset and base
   ========================================================================== */
* { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  background: linear-gradient(180deg, var(--bg-soft) 0, var(--bg) 380px);
  color: var(--text);
  font-family: var(--font);
  font-size: 17px;
  line-height: 1.75;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}
a {
  color: var(--brand);
  text-decoration-thickness: .09em;
  text-underline-offset: .16em;
}
a:hover { color: var(--brand-3); }
img, svg, video, iframe { max-width: 100%; }
img { height: auto; border-radius: 14px; }
button, input, textarea, select { font: inherit; }
button { cursor: pointer; }
::selection { background: var(--warning); color: #21180e; }
.skip-link {
  position: absolute;
  left: 14px;
  top: -70px;
  z-index: 999;
  background: #fff;
  color: #111;
  padding: 10px 14px;
  border-radius: 10px;
  box-shadow: var(--shadow-sm);
}
.skip-link:focus { top: 12px; }
.site-shell {
  max-width: var(--max);
  margin: 0 auto;
  padding: 0 20px;
}
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  white-space: nowrap;
  border: 0;
}

/* ==========================================================================
   03. Header, menu and search
   ========================================================================== */
.top-note {
  background: #fff7e8;
  border-bottom: 1px solid var(--line);
  color: #5d4b35;
  font-size: 14px;
}
.top-note .site-shell {
  display: flex;
  gap: 10px;
  justify-content: center;
  padding-top: 8px;
  padding-bottom: 8px;
}
.site-header {
  position: sticky;
  top: 0;
  z-index: 50;
  background: rgba(255, 253, 248, .94);
  backdrop-filter: saturate(160%) blur(14px);
  border-bottom: 1px solid rgba(232, 223, 210, .9);
}
.header-inner {
  display: flex;
  align-items: center;
  gap: 18px;
  min-height: 74px;
}
.brand-wrap {
  display: flex;
  align-items: center;
  gap: 12px;
  min-width: 0;
}
.brand-mark {
  display: grid;
  place-items: center;
  flex: 0 0 auto;
  width: 42px;
  height: 42px;
  border-radius: 14px;
  background: linear-gradient(135deg, var(--brand), var(--brand-2));
  color: #fff;
  font-weight: 900;
  box-shadow: 0 10px 22px rgba(155, 92, 34, .24);
}
.Header h1,
.Header .title {
  margin: 0;
  font-size: 23px;
  line-height: 1.2;
  letter-spacing: -.04em;
}
.Header h1 a,
.Header .title a {
  color: var(--text);
  text-decoration: none;
}
.Header .description {
  margin: 3px 0 0;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.35;
}
.nav-toggle {
  display: none;
  margin-left: auto;
  border: 1px solid var(--line);
  background: #fff;
  border-radius: 12px;
  padding: 9px 12px;
  color: var(--text);
  font-weight: 800;
}
.nav-area {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 14px;
}
.LinkList ul,
.PageList ul {
  display: flex;
  align-items: center;
  gap: 4px;
  list-style: none;
  margin: 0;
  padding: 0;
}
.LinkList a,
.PageList a {
  display: block;
  padding: 9px 12px;
  border-radius: var(--radius-pill);
  color: #3b332b;
  text-decoration: none;
  font-weight: 700;
  font-size: 14px;
}
.LinkList a:hover,
.PageList a:hover {
  background: #f5ead8;
  color: var(--brand);
}
.search-mini { position: relative; }
.search-mini input {
  width: 190px;
  border: 1px solid var(--line);
  background: #fff;
  border-radius: var(--radius-pill);
  padding: 10px 38px 10px 14px;
  outline: none;
}
.search-mini input:focus {
  border-color: #d0a873;
  box-shadow: 0 0 0 4px rgba(199, 122, 45, .12);
}
.search-mini button {
  position: absolute;
  right: 4px;
  top: 4px;
  border: 0;
  background: var(--brand);
  color: #fff;
  border-radius: var(--radius-pill);
  width: 32px;
  height: 32px;
}

/* ==========================================================================
   04. Layout and homepage cards
   ========================================================================== */
.layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) var(--sidebar);
  gap: var(--gap);
  align-items: start;
  padding-top: 34px;
  padding-bottom: 48px;
}
.main-col { min-width: 0; }
.sidebar {
  position: sticky;
  top: 96px;
  min-width: 0;
}
.hero-card {
  background: linear-gradient(135deg, #fffdf8, #fff3df);
  border: 1px solid var(--line);
  border-radius: var(--radius-xl);
  padding: 34px;
  box-shadow: var(--shadow);
  margin-bottom: 28px;
}
.hero-card h2 {
  margin: 0 0 10px;
  font-size: clamp(28px, 4vw, 44px);
  line-height: 1.15;
  letter-spacing: -.055em;
}
.hero-card p {
  max-width: 760px;
  margin: 0;
  color: #65594d;
}
.trust-strip {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin: -12px 0 26px;
}
.trust-item {
  background: rgba(255,255,255,.72);
  border: 1px solid var(--line);
  border-radius: 16px;
  padding: 13px 14px;
  color: #5a4c3f;
  font-size: 14px;
  font-weight: 800;
}

/* ==========================================================================
   05. Post list
   ========================================================================== */
.post-card {
  display: grid;
  grid-template-columns: 240px minmax(0, 1fr);
  gap: 22px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 24px;
  padding: 18px;
  margin-bottom: 22px;
  box-shadow: var(--shadow);
}
.post-card:hover {
  border-color: #dec59f;
  transform: translateY(-1px);
  transition: transform .18s ease, border-color .18s ease;
}
.post-thumb {
  position: relative;
  display: block;
  aspect-ratio: 16 / 10;
  overflow: hidden;
  border-radius: 18px;
  background: #f2e2c9;
}
.post-thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 0;
}
.fallback-thumb {
  display: grid;
  place-items: center;
  width: 100%;
  height: 100%;
  padding: 18px;
  background:
    radial-gradient(circle at 20% 20%, rgba(255,255,255,.82), transparent 34%),
    linear-gradient(135deg, #f9e4bb, #fff8e8 55%, #dceee9);
  color: #5a3515;
  text-align: center;
  font-weight: 900;
  letter-spacing: -.04em;
  line-height: 1.25;
}
.fallback-thumb span {
  display: -webkit-box;
  -webkit-line-clamp: 4;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.post-card h2 {
  margin: 0 0 8px;
  font-size: 24px;
  line-height: 1.28;
  letter-spacing: -.04em;
}
.post-card h2 a {
  color: var(--text);
  text-decoration: none;
}
.post-card h2 a:hover { color: var(--brand); }
.post-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 12px;
  color: var(--muted);
  font-size: 13px;
  margin-bottom: 10px;
}
.post-snippet {
  color: #554d45;
  font-size: 15px;
}
.label-pill {
  display: inline-flex;
  align-items: center;
  border: 1px solid #ead6ba;
  background: #fff8ed;
  color: #795020;
  border-radius: var(--radius-pill);
  padding: 4px 10px;
  font-size: 12px;
  font-weight: 800;
  text-decoration: none;
}

/* ==========================================================================
   06. Single post typography
   ========================================================================== */
.post {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow);
  padding: clamp(22px, 4vw, 46px);
}
.post-header {
  text-align: left;
  margin-bottom: 24px;
}
.post-title.entry-title {
  font-size: clamp(31px, 5vw, 52px);
  line-height: 1.12;
  letter-spacing: -.06em;
  margin: 0 0 14px;
}
.entry-hero {
  width: 100%;
  margin: 0 0 22px;
  border-radius: 22px;
  box-shadow: var(--shadow-sm);
}
.post-body {
  font-size: 18px;
  line-height: 1.86;
  word-break: keep-all;
}
.post-body > :first-child { margin-top: 0; }
.post-body h2,
.post-body h3,
.post-body h4 {
  scroll-margin-top: 96px;
  letter-spacing: -.045em;
  line-height: 1.28;
  color: #201d19;
}
.post-body h2 {
  margin: 44px 0 16px;
  padding: 0 0 10px;
  border-bottom: 3px solid #ead8bd;
  font-size: 30px;
}
.post-body h2:before {
  content: "";
  display: inline-block;
  width: 10px;
  height: 10px;
  margin-right: 10px;
  border-radius: 50%;
  background: var(--brand);
  vertical-align: middle;
}
.post-body h3 {
  margin: 34px 0 12px;
  font-size: 24px;
  padding-left: 14px;
  border-left: 5px solid var(--accent);
}
.post-body h4 {
  margin: 26px 0 10px;
  font-size: 20px;
  color: #473a2f;
}
.post-body p { margin: 0 0 18px; }
.post-body ul,
.post-body ol {
  padding-left: 1.35em;
  margin: 0 0 22px;
}
.post-body li { margin: 8px 0; }
.post-body strong { color: #1f1b17; }
.post-body mark {
  background: var(--warning);
  padding: .1em .25em;
  border-radius: .35em;
}
.post-body blockquote {
  margin: 28px 0;
  padding: 20px 22px;
  border-left: 5px solid var(--brand);
  background: #fff7e9;
  border-radius: 0 16px 16px 0;
  color: #4a4037;
}
.post-body pre {
  overflow: auto;
  padding: 18px;
  border-radius: 16px;
  background: #2b241e;
  color: #fff6e9;
  font-size: 14px;
}
.post-body code {
  background: #f6ecdc;
  border: 1px solid #eadac4;
  border-radius: 6px;
  padding: 2px 5px;
  font-size: .92em;
}
.post-body pre code {
  background: transparent;
  border: 0;
  padding: 0;
  color: inherit;
}

/* ==========================================================================
   07. Tables, comparison charts and callouts
   ========================================================================== */
.post-body table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  overflow: hidden;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: #fff;
  margin: 24px 0;
  font-size: 15px;
}
.post-body th {
  background: #fbedd6;
  color: #38271a;
  text-align: left;
  font-weight: 900;
}
.post-body th,
.post-body td {
  padding: 13px 14px;
  border-bottom: 1px solid var(--line);
  vertical-align: top;
}
.post-body tr:last-child td { border-bottom: 0; }
.post-body tr:nth-child(even) td { background: #fffaf2; }
.post-body .note-box,
.post-body .tip-box,
.post-body .check-box,
.post-body .caution-box {
  margin: 24px 0;
  padding: 18px 20px;
  border-radius: 18px;
  border: 1px solid var(--line);
}
.post-body .note-box { background: var(--surface-2); }
.post-body .tip-box { background: var(--accent-2); border-color: #cfe7df; }
.post-body .check-box { background: var(--success); border-color: #d3e9cd; }
.post-body .caution-box { background: var(--danger); border-color: #f0d4ce; }
.post-body .pros-cons {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
  margin: 24px 0;
}
.post-body .pros-cons > * {
  border: 1px solid var(--line);
  border-radius: 18px;
  padding: 18px;
  background: #fff;
}

/* ==========================================================================
   08. Affiliate CTA link button for Blogger normal-size linked text
   ========================================================================== */
.post-body a:not(.plain-link) { font-weight: 800; }
.post-body a[style*="font-size: medium"],
.post-body a[style*="font-size:medium"],
.post-body span[style*="font-size: medium"] a,
.post-body span[style*="font-size:medium"] a,
.post-body .cta-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  min-height: 46px;
  margin: 8px 0;
  padding: 12px 20px;
  border-radius: var(--radius-pill);
  background: linear-gradient(135deg, var(--brand), var(--brand-2));
  color: #fff !important;
  text-decoration: none !important;
  box-shadow: 0 12px 24px rgba(155, 92, 34, .24);
  font-weight: 900;
}
.post-body a[style*="font-size: medium"]:after,
.post-body a[style*="font-size:medium"]:after,
.post-body span[style*="font-size: medium"] a:after,
.post-body span[style*="font-size:medium"] a:after,
.post-body .cta-button:after {
  content: "›";
  font-size: 22px;
  line-height: 1;
}
.post-body .cta-button.secondary {
  background: #fff;
  color: var(--brand) !important;
  border: 1px solid #e4c498;
  box-shadow: none;
}

/* ==========================================================================
   09. TOC, share, related posts and ads
   ========================================================================== */
.toc-box {
  display: none;
  margin: 22px 0 30px;
  padding: 18px;
  background: #fff8ed;
  border: 1px solid #ead6ba;
  border-radius: 18px;
}
.toc-box.is-ready { display: block; }
.toc-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin: 0 0 10px;
  font-weight: 900;
}
.toc-box ol { margin: 0; padding-left: 20px; }
.toc-box li { margin: 6px 0; }
.toc-box a { color: #4b3825; text-decoration: none; }
.toc-box a:hover { color: var(--brand); text-decoration: underline; }
.share-row {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin: 28px 0;
}
.native-share,
.copy-link {
  border-radius: var(--radius-pill);
  padding: 12px 18px;
  font-weight: 900;
}
.native-share {
  border: 0;
  background: var(--accent);
  color: #fff;
}
.copy-link {
  border: 1px solid var(--line);
  background: #fff;
  color: var(--text);
}
.related-posts { margin-top: 32px; }
.related-posts h2 {
  margin: 0 0 14px;
  font-size: 23px;
  letter-spacing: -.04em;
}
.related-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
}
.related-item {
  display: block;
  background: #fff;
  border: 1px solid var(--line);
  border-radius: 16px;
  padding: 13px;
  text-decoration: none;
  color: var(--text);
}
.related-item:hover {
  border-color: #d3ad78;
  transform: translateY(-1px);
}
.related-item strong {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.35;
}
.ad-slot {
  display: grid;
  place-items: center;
  min-height: 112px;
  background: repeating-linear-gradient(135deg, #fffaf1, #fffaf1 10px, #fff4e4 10px, #fff4e4 20px);
  border: 1px dashed #d8bd91;
  border-radius: 16px;
  color: #92724d;
  font-size: 13px;
  text-align: center;
  padding: 16px;
  margin: 20px 0;
}
.ad-slot.compact { min-height: 72px; }
.ad-slot.sticky-helper { margin-top: 0; }

/* ==========================================================================
   10. Widgets and sidebar
   ========================================================================== */
.widget {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 20px;
  margin: 0 0 20px;
}
.widget-title,
.sidebar .title,
.footer .title {
  margin: 0 0 13px;
  font-size: 16px;
  letter-spacing: -.02em;
}
.PopularPosts ul,
.Label ul,
.BlogArchive ul,
.LinkList ul {
  list-style: none;
  margin: 0;
  padding: 0;
}
.PopularPosts li,
.Label li,
.BlogArchive li,
.sidebar .LinkList li {
  border-top: 1px solid var(--line);
  padding: 10px 0;
}
.PopularPosts li:first-child,
.Label li:first-child,
.BlogArchive li:first-child,
.sidebar .LinkList li:first-child { border-top: 0; }
.Label a {
  display: inline-flex;
  margin: 4px 6px 4px 0;
  padding: 6px 10px;
  border-radius: var(--radius-pill);
  background: #f7eddd;
  text-decoration: none;
  color: #58412a;
  font-weight: 700;
  font-size: 13px;
}
.profile-img { border-radius: 50%; }
.status-msg-wrap {
  background: #fff8ed;
  border: 1px solid var(--line);
  border-radius: 16px;
  padding: 14px 18px;
  margin-bottom: 20px;
}
.pager {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  margin: 24px 0;
}
.pager a {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius-pill);
  padding: 10px 14px;
  text-decoration: none;
  font-weight: 800;
}
.comment-section { margin-top: 24px; }

/* ==========================================================================
   11. Footer
   ========================================================================== */
.footer {
  border-top: 1px solid var(--line);
  background: #fffaf2;
  padding: 34px 0;
  color: #5d554d;
}
.footer-grid {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr;
  gap: 24px;
}
.footer a { color: #544334; }
.site-credit {
  margin-top: 18px;
  color: var(--muted);
  font-size: 13px;
}

/* ==========================================================================
   12. Responsive and print
   ========================================================================== */
@media (max-width: 1080px) {
  :root { --sidebar: 300px; --gap: 24px; }
  .post-card { grid-template-columns: 220px minmax(0, 1fr); }
}
@media (max-width: 980px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { position: static; }
  .post-card { grid-template-columns: 200px minmax(0, 1fr); }
  .footer-grid { grid-template-columns: 1fr 1fr; }
  .search-mini input { width: 150px; }
  .trust-strip { grid-template-columns: 1fr; }
}
@media (max-width: 760px) {
  body { font-size: 16px; }
  .site-shell { padding: 0 14px; }
  .header-inner { min-height: 64px; }
  .nav-toggle { display: block; }
  .nav-area {
    display: none;
    position: absolute;
    left: 16px;
    right: 16px;
    top: 70px;
    background: #fff;
    border: 1px solid var(--line);
    border-radius: 18px;
    box-shadow: var(--shadow);
    padding: 14px;
  }
  .nav-area.is-open { display: block; }
  .LinkList ul,
  .PageList ul { display: block; }
  .search-mini { margin-top: 10px; }
  .search-mini input { width: 100%; }
  .hero-card { padding: 24px; }
  .post-card { grid-template-columns: 1fr; }
  .post { padding: 20px; border-radius: 20px; }
  .post-body { font-size: 17px; }
  .post-body h2 { font-size: 25px; }
  .post-body h3 { font-size: 21px; }
  .post-body table { display: block; overflow-x: auto; white-space: nowrap; }
  .post-body .pros-cons { grid-template-columns: 1fr; }
  .related-grid { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr; }
}
@media (max-width: 430px) {
  .brand-mark { width: 38px; height: 38px; }
  .Header h1,
  .Header .title { font-size: 20px; }
  .post-card { padding: 14px; border-radius: 20px; }
  .share-row > * { width: 100%; }
}
@media print {
  .site-header,
  .sidebar,
  .share-row,
  .footer,
  .top-note,
  .ad-slot,
  .toc-box { display: none !important; }
  .layout { display: block; }
  .post { box-shadow: none; border: 0; }
}

body.script:
(function () {
  'use strict';

  var nav = document.getElementById('navArea');
  var btn = document.querySelector('.nav-toggle');
  if (btn && nav) {
    btn.addEventListener('click', function () {
      var open = nav.classList.toggle('is-open');
      btn.setAttribute('aria-expanded', open ? 'true' : 'false');
    });
  }

  var body = document.getElementById('postBody');
  var toc = document.getElementById('tocBox');
  var list = document.getElementById('tocList');
  if (body && toc && list) {
    var heads = [].slice.call(body.querySelectorAll('h2,h3'));
    if (heads.length > 1) {
      heads.forEach(function (h, i) {
        if (!h.id) {
          h.id = 'section-' + (i + 1);
        }
        var li = document.createElement('li');
        if (h.tagName === 'H3') {
          li.style.marginLeft = '14px';
        }
        var a = document.createElement('a');
        a.href = '#' + h.id;
        a.textContent = h.textContent.trim();
        li.appendChild(a);
        list.appendChild(li);
      });
      toc.classList.add('is-ready');
    }
  }

  var share = document.querySelector('.native-share');
  var copy = document.querySelector('.copy-link');
  function copyUrl() {
    if (navigator.clipboard) {
      navigator.clipboard.writeText(location.href).then(function () {
        if (copy) {
          copy.textContent = '복사 완료';
          window.setTimeout(function () { copy.textContent = '링크 복사'; }, 1800);
        }
      });
    }
  }
  if (share) {
    share.addEventListener('click', function () {
      if (navigator.share) {
        navigator.share({ title: document.title, url: location.href }).catch(function () {});
      } else {
        copyUrl();
      }
    });
  }
  if (copy) {
    copy.addEventListener('click', copyUrl);
  }

  var related = document.getElementById('relatedGrid');
  if (related) {
    var labels = [].slice.call(document.querySelectorAll('.post-meta .label-pill'))
      .map(function (a) { return a.textContent.trim(); })
      .filter(Boolean);
    var feed = '/feeds/posts/summary?alt=json&max-results=6';
    if (labels[0]) {
      feed = '/feeds/posts/summary/-/' + encodeURIComponent(labels[0]) + '?alt=json&max-results=6';
    }
    fetch(feed)
      .then(function (r) { return r.json(); })
      .then(function (json) {
        var entries = (json.feed && json.feed.entry) || [];
        var current = location.href.replace(/[#?].*/, '');
        entries
          .filter(function (e) {
            var link = (e.link || []).filter(function (l) { return l.rel === 'alternate'; })[0];
            return link && link.href.replace(/[#?].*/, '') !== current;
          })
          .slice(0, 3)
          .forEach(function (e) {
            var link = (e.link || []).filter(function (l) { return l.rel === 'alternate'; })[0];
            var a = document.createElement('a');
            var title = e.title && e.title.$t ? e.title.$t : '관련 글';
            a.className = 'related-item';
            a.href = link.href;
            a.innerHTML = '<strong></strong>';
            a.querySelector('strong').textContent = title;
            related.appendChild(a);
          });
        if (!related.children.length && related.parentNode) {
          related.parentNode.style.display = 'none';
        }
      })
      .catch(function () {
        if (related.parentNode) {
          related.parentNode.style.display = 'none';
        }
      });
  }
}());
